# Try with -a and different options for the unresolved ones
DBG=/tmp/symbols/libmonosgen-2.0.so.dbg
echo "SGen worker - trying with .symtab/.dynsym fallback:"
aarch64-linux-gnu-nm -C "$DBG" 2>/dev/null | awk -v a1=0x2f4b20 -v a2=0x2f4c84 '
/^[0-9a-f]+ [tTwW]/ {
  addr = strtonum("0x"$1)
  size = 0
  name = $3
  addrs[addr] = name
  sorted[++n] = addr
}
END {
  # Sort
  for (i=1; i<=n; i++)
    for (j=i+1; j<=n; j++)
      if (sorted[i] > sorted[j]) { t=sorted[i]; sorted[i]=sorted[j]; sorted[j]=t }

  targets[1] = strtonum(a1)
  targets[2] = strtonum(a2)

  for (t=1; t<=2; t++) {
    target = targets[t]
    best = 0
    for (i=1; i<=n; i++) {
      if (sorted[i] <= target) best = sorted[i]
      else break
    }
    if (best > 0)
      printf "  pc 0x%x => %s+0x%x\n", target, addrs[best], target-best
  }
}' 2>/dev/null

