# These addresses fall in .data.rel.ro, likely the Cortex-A53 erratum thunks
# Let's look at the eh_frame (unwind info) which should map these to actual functions
python3 << 'PYEOF'
from elftools.elf.elffile import ELFFile

targets = [0x2f4b20, 0x2f4c84]

with open("/tmp/sv-symbols/libmonosgen-2.0.so.dbg", "rb") as f:
    elf = ELFFile(f)
    dwarf = elf.get_dwarf_info()

    # Search through all CUs for subprogram DIEs that contain our addresses
    for cu in dwarf.iter_CUs():
        for die in cu.iter_DIEs():
            if die.tag == 'DW_TAG_subprogram':
                if 'DW_AT_low_pc' in die.attributes and 'DW_AT_high_pc' in die.attributes:
                    low = die.attributes['DW_AT_low_pc'].value
                    high_attr = die.attributes['DW_AT_high_pc']
                    # high_pc can be absolute or offset
                    if high_attr.form.startswith('DW_FORM_addr'):
                        high = high_attr.value
                    else:
                        high = low + high_attr.value

                    for t in targets:
                        if low <= t < high:
                            name = die.attributes.get('DW_AT_name')
                            if name:
                                name = name.value.decode() if isinstance(name.value, bytes) else str(name.value)
                            else:
                                name = '<unknown>'
                            print(f"  0x{t:x} => {name} (0x{low:x}-0x{high:x})")
PYEOF

