        print(f"eh_frame found at offset 0x{eh_frame['sh_offset']:x}, size 0x{eh_frame['sh_size']:x}")

    # Try using DWARF info from the debug file

with open("/tmp/sv-symbols/libmonosgen-2.0.so.dbg", "rb") as f:
